import { activityRepository } from "@/repositories/activity.repository";
import type { ActivityType, Prisma } from "@prisma/client";

/* ============================================
   Activity Service
   Business logic layer — calls repositories only.
   ============================================ */

export const activityService = {
  async log(data: {
    userId: string;
    type: ActivityType;
    entity: string;
    entityId: string;
    metadata?: Record<string, unknown>;
  }) {
    return activityRepository.create({
      userId: data.userId,
      type: data.type,
      entity: data.entity,
      entityId: data.entityId,
      metadata: (data.metadata as Prisma.InputJsonValue) ?? undefined,
    });
  },

  async list(params: {
    userId?: string;
    type?: ActivityType;
    entity?: string;
    entityId?: string;
    skip?: number;
    take?: number;
  }) {
    const where: Record<string, unknown> = {};
    if (params.userId !== undefined) where.userId = params.userId;
    if (params.type !== undefined) where.type = params.type;
    if (params.entity !== undefined) where.entity = params.entity;
    if (params.entityId !== undefined) where.entityId = params.entityId;

    return activityRepository.findMany({
      where,
      skip: params.skip,
      take: params.take,
      orderBy: { createdAt: "desc" },
    });
  },

  async count(params: {
    userId?: string;
    type?: ActivityType;
  }) {
    return activityRepository.count({
      userId: params.userId,
      type: params.type,
    });
  },
};

import { prisma } from "@/lib/prisma";
import type { Prisma } from "@prisma/client";

/* ============================================
   Activity Log Repository
   The ONLY layer that interacts with Prisma
   for ActivityLog operations.
   ============================================ */

export type ActivityLogWithRelations = Prisma.ActivityLogGetPayload<{
  include: { user: true };
}>;

export type ActivityLogCreateInput = Prisma.ActivityLogUncheckedCreateInput;
export type ActivityLogWhereInput = Prisma.ActivityLogWhereInput;
export type ActivityLogWhereUniqueInput = Prisma.ActivityLogWhereUniqueInput;

export const activityRepository = {
  findById(id: string) {
    return prisma.activityLog.findUnique({
      where: { id },
      include: { user: true },
    });
  },

  create(data: ActivityLogCreateInput) {
    return prisma.activityLog.create({ data });
  },

  findMany(params: {
    where?: ActivityLogWhereInput;
    skip?: number;
    take?: number;
    orderBy?: Prisma.ActivityLogOrderByWithRelationInput;
  }) {
    return prisma.activityLog.findMany(params);
  },

  count(where?: ActivityLogWhereInput) {
    return prisma.activityLog.count({ where });
  },
};

"use server";

import { projectService } from "@/services/project.service";
import { getCurrentUser } from "@/lib/auth/session";
import type { ProjectStatistics } from "@/types/project";

/* ============================================
   Get Project Details Server Action
   Returns project with statistics and timeline.
   ============================================ */

export async function getProjectDetailsAction(id: string) {
  const user = await getCurrentUser();
  if (!user) return null;

  const project = await projectService.getById(id);
  if (!project) return null;

  const statistics: ProjectStatistics = await projectService.getStatistics(id);

  const timeline = await projectService.getTimeline(id, 20);

  return {
    project,
    statistics,
    timeline,
  };
}

"use client";

import { useRef, useState, useEffect, useCallback } from "react";
import {
  Play,
  Pause,
  Volume2,
  VolumeX,
  Maximize,
  Minimize,
  X,
  Settings,
} from "lucide-react";

import { Button } from "@/components/ui/button";
import { formatDuration } from "@/lib/video/metadata";

/* ============================================
   VideoPlayer — Reusable video player
   Play, Pause, Fullscreen, Seek, Volume,
   Playback Speed, Poster
   ============================================ */

type VideoPlayerProps = {
  src: string;
  title?: string;
  poster?: string;
  onClose?: () => void;
  autoPlay?: boolean;
};

const PLAYBACK_SPEEDS = [0.5, 0.75, 1, 1.25, 1.5, 2];

export function VideoPlayer({
  src,
  title,
  poster,
  onClose,
  autoPlay = false,
}: VideoPlayerProps) {
  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [volume, setVolume] = useState(1);
  const [isMuted, setIsMuted] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [showSpeedMenu, setShowSpeedMenu] = useState(false);
  const [playbackRate, setPlaybackRate] = useState(1);

  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;

    const onTimeUpdate = () => setCurrentTime(video.currentTime);
    const onDurationChange = () => setDuration(video.duration);
    const onPlay = () => setIsPlaying(true);
    const onPause = () => setIsPlaying(false);

    video.addEventListener("timeupdate", onTimeUpdate);
    video.addEventListener("durationchange", onDurationChange);
    video.addEventListener("play", onPlay);
    video.addEventListener("pause", onPause);

    return () => {
      video.removeEventListener("timeupdate", onTimeUpdate);
      video.removeEventListener("durationchange", onDurationChange);
      video.removeEventListener("play", onPlay);
      video.removeEventListener("pause", onPause);
    };
  }, []);

  useEffect(() => {
    const onFullscreenChange = () => {
      setIsFullscreen(document.fullscreenElement === containerRef.current);
    };
    document.addEventListener("fullscreenchange", onFullscreenChange);
    return () => document.removeEventListener("fullscreenchange", onFullscreenChange);
  }, []);

  const togglePlay = useCallback(() => {
    const video = videoRef.current;
    if (!video) return;
    if (isPlaying) video.pause();
    else video.play();
  }, [isPlaying]);

  const handleSeek = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    const video = videoRef.current;
    if (!video) return;
    const time = Number(e.target.value);
    video.currentTime = time;
    setCurrentTime(time);
  }, []);

  const handleVolume = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    const video = videoRef.current;
    if (!video) return;
    const vol = Number(e.target.value);
    video.volume = vol;
    video.muted = vol === 0;
    setVolume(vol);
    setIsMuted(vol === 0);
  }, []);

  const toggleMute = useCallback(() => {
    const video = videoRef.current;
    if (!video) return;
    video.muted = !video.muted;
    setIsMuted(video.muted);
  }, []);

  const toggleFullscreen = useCallback(() => {
    const container = containerRef.current;
    if (!container) return;
    if (document.fullscreenElement) {
      document.exitFullscreen();
    } else {
      container.requestFullscreen();
    }
  }, []);

  const changePlaybackRate = useCallback((rate: number) => {
    const video = videoRef.current;
    if (!video) return;
    video.playbackRate = rate;
    setPlaybackRate(rate);
    setShowSpeedMenu(false);
  }, []);

  const progress = duration > 0 ? (currentTime / duration) * 100 : 0;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 p-4">
      {/* Close button */}
      {onClose && (
        <Button
          variant="ghost"
          size="icon"
          className="absolute end-4 top-4 z-10 text-white hover:bg-white/10"
          onClick={onClose}
          aria-label="إغلاق"
        >
          <X className="h-5 w-5" />
        </Button>
      )}

      {/* Title */}
      {title && (
        <div className="absolute start-4 top-4 z-10">
          <p className="text-sm font-medium text-white">{title}</p>
        </div>
      )}

      <div ref={containerRef} className="relative w-full max-w-5xl">
        <video
          ref={videoRef}
          src={src}
          poster={poster}
          autoPlay={autoPlay}
          className="w-full rounded-lg"
          onClick={togglePlay}
        />

        {/* Controls overlay */}
        <div className="absolute bottom-0 left-0 right-0 space-y-2 rounded-b-lg bg-gradient-to-t from-black/80 to-transparent p-4">
          {/* Seek bar */}
          <div className="flex items-center gap-2">
            <span className="text-xs text-white">
              {formatDuration(currentTime)}
            </span>
            <input
              type="range"
              min={0}
              max={duration || 0}
              value={currentTime}
              onChange={handleSeek}
              className="flex-1 accent-primary"
              aria-label="الانتقال"
            />
            <span className="text-xs text-white">
              {formatDuration(duration)}
            </span>
          </div>

          {/* Buttons */}
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <Button
                variant="ghost"
                size="icon"
                className="h-8 w-8 text-white hover:bg-white/10"
                onClick={togglePlay}
                aria-label={isPlaying ? "إيقاف مؤقت" : "تشغيل"}
              >
                {isPlaying ? <Pause className="h-4 w-4" /> : <Play className="h-4 w-4" />}
              </Button>

              {/* Volume */}
              <div className="flex items-center gap-1">
                <Button
                  variant="ghost"
                  size="icon"
                  className="h-8 w-8 text-white hover:bg-white/10"
                  onClick={toggleMute}
                  aria-label={isMuted ? "تشغيل الصوت" : "كتم الصوت"}
                >
                  {isMuted ? <VolumeX className="h-4 w-4" /> : <Volume2 className="h-4 w-4" />}
                </Button>
                <input
                  type="range"
                  min={0}
                  max={1}
                  step={0.05}
                  value={isMuted ? 0 : volume}
                  onChange={handleVolume}
                  className="w-20 accent-primary"
                  aria-label="مستوى الصوت"
                />
              </div>

              {/* Playback speed */}
              <div className="relative">
                <Button
                  variant="ghost"
                  size="icon"
                  className="h-8 w-8 text-white hover:bg-white/10"
                  onClick={() => setShowSpeedMenu((s) => !s)}
                  aria-label="سرعة التشغيل"
                >
                  <Settings className="h-4 w-4" />
                </Button>
                {showSpeedMenu && (
                  <div className="absolute bottom-full end-0 mb-2 rounded-lg border bg-popover p-1 shadow-lg">
                    {PLAYBACK_SPEEDS.map((rate) => (
                      <button
                        key={rate}
                        onClick={() => changePlaybackRate(rate)}
                        className={`block w-full rounded px-3 py-1.5 text-xs transition-colors hover:bg-accent ${
                          playbackRate === rate ? "font-bold text-primary" : ""
                        }`}
                      >
                        {rate}x
                      </button>
                    ))}
                  </div>
                )}
              </div>
            </div>

            {/* Fullscreen */}
            <Button
              variant="ghost"
              size="icon"
              className="h-8 w-8 text-white hover:bg-white/10"
              onClick={toggleFullscreen}
              aria-label={isFullscreen ? "إنهاء ملء الشاشة" : "ملء الشاشة"}
            >
              {isFullscreen ? <Minimize className="h-4 w-4" /> : <Maximize className="h-4 w-4" />}
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
}

import { STORAGE_CONFIG } from "./config";
import { CloudflareR2Provider } from "./cloudflare-r2.provider";
import type { StorageProvider } from "./provider";
